func:
msg.tags = {
    dispositivo: "ESP32",
    ubicacion: "sala_maquinas"
};

msg.fields = {
    flujo: Number(msg.payload)
};

return msg;

var flujo = Number(msg.payload);
var ahora = new Date();

// Ajuste hora Colombia (UTC-5)
ahora.setHours(ahora.getHours() - 5);
var hora = ahora.getHours();
var minuto = ahora.getMinutes();

var esHorarioEvaluacion = (hora >= 0 && hora < 5);

// Umbral mínimo real del sensor YF-S201
var UMBRAL_MINIMO = 0.07;

var DURACION_ANOMALIA_MS = 30 * 60 * 1000;

// ¿Hay flujo real detectable?
if (flujo >= UMBRAL_MINIMO && esHorarioEvaluacion) {
    var inicio = context.get('inicioFlujo') || ahora.getTime();
    context.set('inicioFlujo', inicio);

    var duracionMs = ahora.getTime() - inicio;

    if (duracionMs >= DURACION_ANOMALIA_MS) {
        var alertaEnviada = context.get('alertaEnviada') || false;

        if (!alertaEnviada) {
            context.set('alertaEnviada', true);

            var dia = ahora.getDate().toString().padStart(2, '0');
            var mes = (ahora.getMonth() + 1).toString().padStart(2, '0');
            var anio = ahora.getFullYear();
            var horas = ahora.getHours().toString().padStart(2, '0');
            var minutos = ahora.getMinutes().toString().padStart(2, '0');
            var segundos = ahora.getSeconds().toString().padStart(2, '0');

            var duracionSeg = Math.round(duracionMs / 1000);

            msg.topic = "⚠️ ALERTA: Posible anomalía de consumo de agua";
            msg.payload =
                "ALERTA DE CONSUMO ANÓMALO\n\n" +
                "Se detectó flujo continuo en horario de evaluación.\n\n" +
                "Caudal actual: " + flujo + " L/min\n" +
                "Duración del flujo: " + duracionSeg + " segundos\n" + // en pruebas muestra segundos
                "Hora de detección: " + dia + "/" + mes + "/" + anio + " " + horas + ":" + minutos + ":" + segundos + "\n\n" +
                "Posible causa: fuga activa o llave dejada abierta.\n\n" +
                "Sistema IoT - Monitoreo de Agua - Bucaramanga";

            return msg;
        }
    }
} else {
    // Flujo interrumpido, bajo el mínimo, o fuera del horario → reiniciar
    context.set('inicioFlujo', null);
    context.set('alertaEnviada', false);
}

return null;
